VALUES
  ('generalpolice-94737317-moex-00292', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '硫磺、碳粉及過氯酸鉀為一般火藥中常見的成分，有關此等火藥之敘述，下列何者錯誤？', '["為預混型態的固態燃料", "碳粉作為燃料用", "過氯酸鉀作為氧化劑", "須有充分氧氣才能起燃爆炸"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9d177b85cce5", "answer_pdf_sha1": "272e65e9587d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00293', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '有關影響粉塵爆炸的因素，下列敘述何者錯誤？', '["粉塵之最小發火能量，通常與壓力、溫度成反比", "粉塵粒子最小發火能量與粉塵粒徑成正比", "粉塵粒子含水量愈大愈活潑，愈容易爆炸", "粉塵粒子之表面積與質量比愈大，愈容易爆炸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9d177b85cce5", "answer_pdf_sha1": "272e65e9587d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00294', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '爆炸時火焰面之傳播非常快速，火焰面與其前方進行之壓縮波所生之衝擊波融合，形成一個速度 達音速的波，此爆炸現象稱為：', '["閃燃", "爆燃", "爆轟", "音爆"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9d177b85cce5", "answer_pdf_sha1": "272e65e9587d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00295', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '下列選項，完全沒有冗贅詞語的句子是：', '["這是全臺第一次首見且獨一無二的咖啡廳，供應著各國的咖啡", "全民戮力同心抵抗外敵侵略，卻有少數人爭功諉過，真是要不得", "此次投入市場，希望能夠擴充放大原本的優勢，提供更多美味選擇", "發自內在衷心期盼每一位孩子都能健康平安的長大，父母不再面臨錐心之痛"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "cf19bfee6060", "answer_pdf_sha1": "e24703051873", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00296', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '下列「」中使用之量詞，何者錯誤？', '["那位留著三「綹」雪白鬍鬚的長者，將一「抔」黃土撒向大海", "長工在穀倉裡挑了一「擔」穀子，又偷偷飲了一「盅」酒，沒走多遠就挑不動了", "這一「幀幀」照片記錄著我們共同經歷的一「樁樁」事件，見證了我倆深厚的友誼", "他不但精通英文，更說得一「席」流利的法語，憑藉優越的外語能力通過一「道 道」關卡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "cf19bfee6060", "answer_pdf_sha1": "e24703051873", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00297', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「河粉是潮汕特產，隨著移民從嶺南傳到東南亞各地，在名稱和口味裡留下播遷痕 跡。香港簡稱為『河』，越南人叫Pho，泰國和馬來都叫粿條（KwayTeow），和 粥（Joak）一樣來自潮語。好笑的是，這 KwayTeow 出口轉內銷，回流到香港被 譯為『貴刁』，茶餐廳觸目可見『馬來炒貴刁』。原來河粉不止是我的懷舊，也是 許多亞洲人的鄉愁，它是米漿做成的通行證，一路逶迤穿過南方，出入市井爐灶， 沾滿平民滋味，悠悠不盡如灌稻之水。」 根據上文，下列選項何者正確？', '["所有亞洲國家都具有相同的米食文化", "河粉這種食物，只有在市井之中才能吃到", "米漿製成的產品，可能是若干亞洲人味蕾共同擁有的記憶", "即使河粉在不同國家擁有不同的名稱，但料理的味道皆極其相似"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "cf19bfee6060", "answer_pdf_sha1": "e24703051873", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00298', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「『學而時習之』，說明學問要適時、按時、時時去追求。孔子說的『學』，不只 是指追求書本上的學問，而且也指實踐做人的道理，所以這裡所說的『習』，有溫 習、也有實踐的意思。一個人對於他所求得的學識，能夠時加溫習，就往往能夠溫 故而知新，體會出新的道理來。」 根據上文，下列選項最接近文意的是：', '["按部就班學習固然重要，但讀萬卷書不如行萬里路", "學習的真諦是在反覆實踐中觸類旁通，獲得新啟發", "學海無涯，唯有活到老學到老才能免於被社會淘汰", "如果不能把學識應用在做人處事上，就枉讀聖賢書"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "cf19bfee6060", "answer_pdf_sha1": "e24703051873", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00299', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '一份電腦的「使用手冊」，應具備該電腦軟硬體設備規格的「規格說明」，並須有 具體的「使用方法」；另有維護廠商利益的「版權說明」、「免責聲明」；以及維 護使用者安全的「安全說明」、「注意事項」等等。擷取一頁部分內文如下：「在 法律允許的範圍內，本公司就本使用手冊，不提供任何明示或默示的擔保及保證， 包括但不限於商業適銷性、特定目的之適用性、未侵害任何他人權利及任何得使用 本使用手冊或無法使用本使用手冊的保證，且本公司對因使用本使用手冊而獲取的 結果或透過本使用手冊所獲得任何資訊之準確性或可靠性不提供擔保。……當下列 兩種情況發生時，本產品將不再受到本公司之保固及服務：（1）本產品曾經過非 授權之維修、規格更改、零件替換或其他未經過本公司授權的行為。（2）本產品 序號模糊不清或喪失。」 上述內容最可能出現在「使用手冊」的那一部分？', '["使用方法", "版權說明", "免責說明", "安全說明"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "cf19bfee6060", "answer_pdf_sha1": "e24703051873", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00300', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「第一堂課，濟之師就提出一個問題：『在一片草坪上，如何尋找一枚小球？』同 學們誰也不敢出聲。他老人家慢條斯理的自己回答：『在草坪上，畫上一條一條的 平行直線，沿線一條一條的走過，低頭仔細看，走完整個草坪，一定會找到這個小 球。』他的這一段話，毋寧為學生指示了學術研究與處世治事的基本原則：按照最 笨最累的辦法，卻是最有把握找到問題的癥結所在。」 下列選項，何者最切合上文所揭櫫的觀念？', '["鉅細靡遺，無所疏漏", "按部就班，照表操課", "凡事豫則立，不豫則廢", "不以規矩，不能成方圓"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "cf19bfee6060", "answer_pdf_sha1": "e24703051873", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00301', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '田納西．威廉斯說：「我的作品記錄了我各個時期的情感。它們與我的真實人生沒 有任何關聯，但卻能反映我各階段的情緒。我試著要自己天天寫作，因為除了寫作 之外，我沒有任何慰藉。當你處於低潮時——戀情不順、痛失親人，或生活中出現 其他失序狀況——除了寫作之外，你無處可逃。」 根據上文，最貼近本文旨意的選項是：', '["寫作的前提是痛苦經歷", "寫作的當下是充滿回憶", "寫作的歷程是一種療癒", "寫作的結果是完成傳記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "cf19bfee6060", "answer_pdf_sha1": "e24703051873", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
